import{_ as a,o as s,c as t,a0 as i}from"./chunks/framework.BH9V8Et6.js";const k=JSON.parse('{"title":"Backends","description":"","frontmatter":{},"headers":[],"relativePath":"reference/backends.md","filePath":"reference/backends.md"}'),r={name:"reference/backends.md"};function o(n,e,c,h,l,d){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="backends" tabindex="-1">Backends <a class="header-anchor" href="#backends" aria-label="Permalink to &quot;Backends&quot;">​</a></h1><p>ketch has three search surfaces, each with its own backends: web search (<code>ketch search</code>), code search (<code>ketch code</code>), and library docs (<code>ketch docs</code>).</p><h2 id="web-search-backends" tabindex="-1">Web Search Backends <a class="header-anchor" href="#web-search-backends" aria-label="Permalink to &quot;Web Search Backends&quot;">​</a></h2><p>ketch supports six web-search backends. Set the default with <code>ketch config set backend &lt;name&gt;</code>. To query several at once, use <code>ketch search --multi</code> (rank-fused federation) or <code>--random</code> (one shuffled provider with fallback) — see the <a href="/ketch/reference/commands#ketch-search">command reference</a>.</p><p>Every keyed backend also accepts a pool of keys (<code>brave_api_keys</code>, <code>exa_api_keys</code>, <code>firecrawl_api_keys</code>, <code>keenable_api_keys</code>); ketch picks one at random per request and retries once with a different key on <code>401</code>/<code>429</code> (<code>402</code> for Firecrawl). See <a href="/ketch/guide/configuration#multiple-api-keys-per-provider">multiple API keys</a>.</p><h2 id="brave-default" tabindex="-1">Brave (default) <a class="header-anchor" href="#brave-default" aria-label="Permalink to &quot;Brave (default)&quot;">​</a></h2><p>Brave Search offers a free API tier — no scraping, proper JSON API, reliable.</p><p><strong>Setup:</strong></p><ol><li>Get a free API key at <a href="https://brave.com/search/api/" target="_blank" rel="noreferrer">brave.com/search/api</a></li><li>Set it: <code>ketch config set brave_api_key &lt;your-key&gt;</code></li></ol><p><strong>Free tier limits:</strong> 2,000 queries/month, 1 query/second.</p><h2 id="duckduckgo" tabindex="-1">DuckDuckGo <a class="header-anchor" href="#duckduckgo" aria-label="Permalink to &quot;DuckDuckGo&quot;">​</a></h2><p>Zero-config HTML scraping of DuckDuckGo&#39;s search results. No API key needed.</p><p><strong>Setup:</strong> None — works out of the box.</p><p><strong>Limitations:</strong> DuckDuckGo aggressively rate-limits automated requests. You may see <code>ddg rate limited after retries</code> errors under heavy use. ketch retries up to 3 times with 500ms backoff.</p><h2 id="searxng" tabindex="-1">SearXNG <a class="header-anchor" href="#searxng" aria-label="Permalink to &quot;SearXNG&quot;">​</a></h2><p>Self-hosted metasearch engine with a JSON API. The most reliable option for heavy use.</p><p><strong>Setup:</strong></p><ol><li>Run a SearXNG instance (Docker is easiest):</li></ol><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 8081:8080</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> searxng/searxng</span></span></code></pre></div><ol start="2"><li><p>Enable JSON format in SearXNG settings (required for the API).</p></li><li><p>Point ketch to it:</p></li></ol><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ketch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backend</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> searxng</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ketch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> searxng_url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8081</span></span></code></pre></div><p><strong>Recommended for:</strong> operators running agents that search frequently, or anyone who wants full control over their search infrastructure.</p><h2 id="exa" tabindex="-1">Exa <a class="header-anchor" href="#exa" aria-label="Permalink to &quot;Exa&quot;">​</a></h2><p>AI-oriented web search via Exa&#39;s hosted MCP endpoint. It works without configuration by default, with an optional Exa API key for authenticated usage.</p><p><strong>Setup:</strong> None for hosted MCP. Optional key:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ketch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exa_api_key</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">your-ke</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ketch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backend</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exa</span></span></code></pre></div><p><strong>Recommended for:</strong> agent workflows that benefit from Exa&#39;s clean result snippets and content-oriented search output.</p><h2 id="firecrawl" tabindex="-1">Firecrawl <a class="header-anchor" href="#firecrawl" aria-label="Permalink to &quot;Firecrawl&quot;">​</a></h2><p>Web search via the <a href="https://firecrawl.dev" target="_blank" rel="noreferrer">Firecrawl</a> v2 <a href="https://docs.firecrawl.dev/api-reference/endpoint/search" target="_blank" rel="noreferrer">search API</a> — proper JSON API, no scraping. Requires an API key.</p><p><strong>Setup:</strong></p><ol><li>Get an API key at <a href="https://firecrawl.dev" target="_blank" rel="noreferrer">firecrawl.dev</a></li><li>Set it: <code>ketch config set firecrawl_api_key &lt;your-key&gt;</code></li><li>Make it the default: <code>ketch config set backend firecrawl</code></li></ol><p><strong>Recommended for:</strong> operators already using Firecrawl for scraping who want a single provider for both search and page extraction. Pair with <code>--scrape</code> to fetch full content per result.</p><h2 id="keenable" tabindex="-1">Keenable <a class="header-anchor" href="#keenable" aria-label="Permalink to &quot;Keenable&quot;">​</a></h2><p>Web search built for AI agents, backed by the Keenable index. Keyless by default — it works with no account or key against the public endpoint (rate-limited); an optional API key lifts the hourly cap.</p><p><strong>Setup:</strong> None. Optional key to lift the rate limit:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ketch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keenable_api_key</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">your-ke</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ketch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backend</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keenable</span></span></code></pre></div><p>Create a key at <a href="https://keenable.ai/console" target="_blank" rel="noreferrer">keenable.ai/console</a>.</p><p><strong>Recommended for:</strong> agent workflows that want a zero-config, agent-oriented search backend without provisioning a provider key up front.</p><h2 id="code-search-backends" tabindex="-1">Code Search Backends <a class="header-anchor" href="#code-search-backends" aria-label="Permalink to &quot;Code Search Backends&quot;">​</a></h2><p><code>ketch code</code> searches real source code across open-source repositories. Set the default with <code>ketch config set code_backend &lt;name&gt;</code>.</p><h3 id="grep-default" tabindex="-1">Grep (default) <a class="header-anchor" href="#grep-default" aria-label="Permalink to &quot;Grep (default)&quot;">​</a></h3><p>The Grep MCP server (<code>mcp.grep.app</code>) — literal or regex search over 1M+ public GitHub repos. Zero config, no token.</p><p><strong>Setup:</strong> None — works out of the box.</p><p>Use <code>--regex</code> to interpret the query as a regular expression.</p><h3 id="sourcegraph" tabindex="-1">Sourcegraph <a class="header-anchor" href="#sourcegraph" aria-label="Permalink to &quot;Sourcegraph&quot;">​</a></h3><p>Grep-style search across ~1M OSS repos with exact line matches over an SSE stream. Results are filtered to non-archived, non-fork repos by default. Supports <code>--regex</code>.</p><p><strong>Setup:</strong> None for the public instance. For a self-hosted instance: <code>ketch config set sourcegraph_url &lt;url&gt;</code>.</p><h3 id="github" tabindex="-1">GitHub <a class="header-anchor" href="#github" aria-label="Permalink to &quot;GitHub&quot;">​</a></h3><p>GitHub Code Search (REST <code>/search/code</code>) with a batched GraphQL call for star counts.</p><p><strong>Setup:</strong> A token is required. Resolution chain: <code>ketch config set github_token &lt;tok&gt;</code> → <code>$GITHUB_TOKEN</code> → <code>$GH_TOKEN</code> → <code>gh auth token</code> (if the <code>gh</code> CLI is installed).</p><p><strong>Limits:</strong> 30 requests/minute. Token must have <code>repo</code> scope.</p><h2 id="docs-backends" tabindex="-1">Docs Backends <a class="header-anchor" href="#docs-backends" aria-label="Permalink to &quot;Docs Backends&quot;">​</a></h2><p><code>ketch docs</code> fetches library documentation. Set the default with <code>ketch config set docs_backend &lt;name&gt;</code>.</p><h3 id="context7-default" tabindex="-1">Context7 (default) <a class="header-anchor" href="#context7-default" aria-label="Permalink to &quot;Context7 (default)&quot;">​</a></h3><p>Curated, version-aware documentation snippets.</p><p><strong>Setup:</strong> Free key: <code>ketch config set context7_api_key &lt;key&gt;</code>.</p><h3 id="local" tabindex="-1">Local <a class="header-anchor" href="#local" aria-label="Permalink to &quot;Local&quot;">​</a></h3><p>A planned FTS5 SQLite backend for offline/private docs. Not yet implemented.</p>`,58)])])}const g=a(r,[["render",o]]);export{k as __pageData,g as default};
